SELECT MAX(output_score) AS max_output_score
FROM knowledge_outputs
WHERE year = 2023;

SELECT country_id, innovation_input_index
FROM innovation_indices
WHERE year = 2023;

SELECT output_score, year
FROM knowledge_outputs
WHERE year = 2023;

SELECT AVG(human_capital_score) AS average_human_capital_score
FROM human_capital
WHERE year = 2023;

SELECT SUM(patents_granted) AS total_patents_granted
FROM knowledge_outputs
WHERE country_id = 0 AND year = 2023;

SELECT AVG(sophistication_score) AS average_sophistication_score
FROM market_sophistication
WHERE year = 2023;

SELECT sophistication_score
FROM market_sophistication
WHERE year = 2023;

SELECT AVG(innovation_input_index) AS avg_innovation_input_index
FROM innovation_indices
WHERE year = 2023;
